import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import ProjectList from '../components/Projects/ProjectList';
import TaskList from '../components/Tasks/TaskList';
import TaskForm from '../components/Tasks/TaskForm';
import { useAuth } from '../context/AuthContext';

const Dashboard = ({ projects: initialProjects, tasks: initialTasks, users }) => {
  const { currentUser } = useAuth();
  const [tasks, setTasks] = useState(initialTasks || []);
  const [projects, setProjects] = useState(initialProjects || []);
  const [showTaskForm, setShowTaskForm] = useState(false);
  const [recentActivities, setRecentActivities] = useState([]);
  const navigate = useNavigate();

  // Initialize with sample data if empty
  useEffect(() => {
    if (!initialProjects || initialProjects.length === 0) {
      setProjects([
        { id: 1, name: 'Website Redesign', description: 'Redesign company website' },
        { id: 2, name: 'Mobile App', description: 'Develop mobile application' },
      ]);
    }
    if (!initialTasks || initialTasks.length === 0) {
      setTasks([
        { 
          id: 1, 
          title: 'Design homepage', 
          description: 'Create new homepage design', 
          status: 'In Progress',
          due_date: '2023-12-31',
          project_id: 1,
          assignee_id: currentUser.id,
          created_at: new Date().toISOString()
        }
      ]);
    }
  }, [initialProjects, initialTasks, currentUser.id]);

  const stats = {
    totalProjects: projects.length,
    totalTasks: tasks.length,
    completedTasks: tasks.filter(task => task.status === 'Completed').length,
    inProgressTasks: tasks.filter(task => task.status === 'In Progress').length,
    myTasks: tasks.filter(task => task.assignee_id === currentUser.id).length
  };

  const recentTasks = [...tasks].sort((a, b) => new Date(b.created_at) - new Date(a.created_at)).slice(0, 5);
  const myRecentTasks = tasks
    .filter(task => task.assignee_id === currentUser.id)
    .sort((a, b) => new Date(b.created_at) - new Date(a.created_at))
    .slice(0, 3);

  const handleCreateTask = (newTask) => {
    const taskWithId = {
      ...newTask,
      id: Date.now(),
      created_at: new Date().toISOString(),
      updated_at: new Date().toISOString()
    };

    setTasks(prevTasks => [...prevTasks, taskWithId]);

    // Add to recent activities
    const activity = {
      id: Date.now(),
      type: 'task_created',
      message: `New task "${newTask.title}" was created`,
      timestamp: new Date().toISOString()
    };

    setRecentActivities(prev => [activity, ...prev].slice(0, 5));
    setShowTaskForm(false);
  };

  const handleTaskStatusChange = (taskId, newStatus) => {
    setTasks(prevTasks => 
      prevTasks.map(task => 
        task.id === taskId ? { ...task, status: newStatus } : task
      )
    );
  };

  const handleViewAllTasks = () => {
    navigate('/my-tasks');
  };

  const handleViewProject = (projectId) => {
    navigate(`/projects/${projectId}`);
  };

  // Format time for activity items
  const formatTimeAgo = (dateString) => {
    const now = new Date();
    const date = new Date(dateString);
    const diffInSeconds = Math.floor((now - date) / 1000);

    if (diffInSeconds < 60) return 'just now';
    if (diffInSeconds < 3600) return `${Math.floor(diffInSeconds / 60)} minutes ago`;
    if (diffInSeconds < 86400) return `${Math.floor(diffInSeconds / 3600)} hours ago`;
    return `${Math.floor(diffInSeconds / 86400)} days ago`;
  };

  return (
    <div className="dashboard">
      <div className="dashboard-header">
        <div>
          <h1>Welcome back, {currentUser.name}! 👋</h1>
          <p>Here's what's happening with your projects today.</p>
        </div>
        <button 
          className="btn btn-primary"
          onClick={() => setShowTaskForm(true)}
        >
          + New Task
        </button>
      </div>

      {showTaskForm && (
        <div className="modal-overlay" onClick={(e) => e.target === e.currentTarget && setShowTaskForm(false)}>
          <div className="modal-content">
            <div className="modal-header">
              <h2>Create New Task</h2>
              <button 
                className="close-button" 
                onClick={() => setShowTaskForm(false)}
                aria-label="Close modal"
              >
                &times;
              </button>
            </div>
            <TaskForm 
              projects={projects} 
              users={users} 
              onSubmit={handleCreateTask}
              onCancel={() => setShowTaskForm(false)}
            />
          </div>
        </div>
      )}

      {/* Statistics Grid */}
      <div className="stats-grid">
        <div className="stat-card" onClick={() => navigate('/projects')}>
          <div className="stat-icon">📁</div>
          <div className="stat-content">
            <h3>{stats.totalProjects}</h3>
            <p>Total Projects</p>
          </div>
        </div>
        <div className="stat-card" onClick={() => navigate('/my-tasks')}>
          <div className="stat-icon">✅</div>
          <div className="stat-content">
            <h3>{stats.totalTasks}</h3>
            <p>Total Tasks</p>
          </div>
        </div>
        <div className="stat-card" onClick={() => navigate('/my-tasks?status=in-progress')}>
          <div className="stat-icon">🚀</div>
          <div className="stat-content">
            <h3>{stats.inProgressTasks}</h3>
            <p>In Progress</p>
          </div>
        </div>
        <div className="stat-card" onClick={() => navigate('/my-tasks?assignee=me')}>
          <div className="stat-icon">🎯</div>
          <div className="stat-content">
            <h3>{stats.myTasks}</h3>
            <p>My Tasks</p>
          </div>
        </div>
      </div>

      <div className="dashboard-content">
        {/* My Recent Tasks */}
        <section className="dashboard-section">
          <div className="section-header">
            <h2>My Recent Tasks</h2>
            <button 
              className="view-all"
              onClick={handleViewAllTasks}
            >
              View All
            </button>
          </div>
          <TaskList 
            tasks={myRecentTasks} 
            users={users} 
            projects={projects}
            onStatusChange={handleTaskStatusChange}
          />
        </section>

        {/* All Projects */}
        <section className="dashboard-section">
          <div className="section-header">
            <h2>All Projects</h2>
            <span className="project-count">{projects.length} projects</span>
          </div>
          <ProjectList 
            projects={projects} 
            users={users}
            onProjectClick={handleViewProject}
          />
        </section>

        {/* Recent Activity */}
        <section className="dashboard-section">
          <div className="section-header">
            <h2>Recent Activity</h2>
          </div>
          <div className="activity-list">
            {recentActivities.length > 0 ? (
              recentActivities.map(activity => (
                <div key={activity.id} className="activity-item">
                  <span className="activity-icon">
                    {activity.type === 'task_created' ? '➕' : '✅'}
                  </span>
                  <div className="activity-content">
                    <p>{activity.message}</p>
                    <span className="activity-time">
                      {formatTimeAgo(activity.timestamp)}
                    </span>
                  </div>
                </div>
              ))
            ) : (
              <div className="activity-item">
                <span className="activity-icon">ℹ️</span>
                <div className="activity-content">
                  <p>No recent activities</p>
                </div>
              </div>
            )}
          </div>
        </section>
      </div>
    </div>
  );
};

export default Dashboard;
